# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

object AccountManager {
  case class Deposit(amount: Double)
  case class Withdraw(amount: Double)
  case object GetBalance
}

class AccountManager extends Actor {
  import AccountManager._

  var balance = 0.0

  def receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! s"Deposited $amount. New balance is $balance"

    case Withdraw(amount) =>
      if (amount <= balance) {
        balance -= amount
        sender() ! s"Withdrew $amount. New balance is $balance"
      } else {
        sender() ! "Insufficient funds"
      }

    case GetBalance =>
      sender() ! s"Current balance is $balance"
  }
}

object Main extends App {
  val system = ActorSystem("AccountManagement")
  val accountManager = system.actorOf(Props[AccountManager], name = "accountManager")

  // Example usage
  accountManager ! Deposit(100.0)
  accountManager ! Withdraw(50.0)
  accountManager ! GetBalance

  system.terminate()
}